import{_ as t,o as a,c as i,aQ as n}from"./chunks/framework.cDvftfeu.js";const m=JSON.parse('{"title":"Schedule","description":"Manage schedule items with due-date reminders and calendar sync.","frontmatter":{"description":"Manage schedule items with due-date reminders and calendar sync."},"headers":[],"relativePath":"en/handbook/schedule.md","filePath":"en/handbook/schedule.md","lastUpdated":1777525243000}'),o={name:"en/handbook/schedule.md"};function r(s,e,d,l,h,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /handbook/schedule.md for this page in Markdown format</div><h1 id="schedule" tabindex="-1">Schedule <a class="header-anchor" href="#schedule" aria-label="Permalink to &quot;Schedule&quot;">​</a></h1><p>On the schedule page, you can view all schedule items, and add or delete them.</p><h2 id="nearest-schedule" tabindex="-1">Nearest Schedule <a class="header-anchor" href="#nearest-schedule" aria-label="Permalink to &quot;Nearest Schedule&quot;">​</a></h2><p>When you enter the schedule page, the nearest upcoming (non-expired) schedule item is displayed at the top, including the name, time, location, and a countdown to the start time. If the item is linked to a course, the course name is also shown.</p><p>Tap the nearest schedule card to view its details.</p><h2 id="schedule-groups" tabindex="-1">Schedule Groups <a class="header-anchor" href="#schedule-groups" aria-label="Permalink to &quot;Schedule Groups&quot;">​</a></h2><p>You can create groups to organize your schedule items. Groups are shown above the schedule list; tap a group to filter items in that group. Each group can have a custom name and icon.</p><h2 id="add-a-schedule-item" tabindex="-1">Add a Schedule Item <a class="header-anchor" href="#add-a-schedule-item" aria-label="Permalink to &quot;Add a Schedule Item&quot;">​</a></h2><p>Tap the &quot;+&quot; button in the top-right corner to add a new item. When adding, you can set:</p><ul><li><strong>Name</strong>: The title of the item (required)</li><li><strong>Location</strong>: Where the event takes place</li><li><strong>Notes</strong>: Additional details</li><li><strong>Target time</strong>: The start time of the event</li><li><strong>End time</strong>: Optional; the end time (must be within 24 hours of the start time)</li><li><strong>Group</strong>: Assign the item to a group</li><li><strong>Reminder</strong>: Get notified before the event starts — options include 10 minutes, 30 minutes, 1 hour, 2 hours, 4 hours, or 8 hours</li><li><strong>Repeat</strong>: Set a repeat rule — daily, weekly, or monthly — with a configurable end date</li><li><strong>Linked course</strong>: Associate the item with a course from your timetable</li></ul><h2 id="edit-and-delete" tabindex="-1">Edit and Delete <a class="header-anchor" href="#edit-and-delete" aria-label="Permalink to &quot;Edit and Delete&quot;">​</a></h2><p>Tap a schedule item in the list to view its details. In the detail popup, you can:</p><ul><li>Tap the settings button to edit the item</li><li>Tap the delete button to remove it</li><li>If the item has a repeat rule, you can choose to delete all related repeat items</li></ul><h2 id="system-calendar-integration-ios" tabindex="-1">System Calendar Integration (iOS) <a class="header-anchor" href="#system-calendar-integration-ios" aria-label="Permalink to &quot;System Calendar Integration (iOS)&quot;">​</a></h2><p>After adding or editing a schedule item, Ham automatically syncs it to the system calendar (calendar name: &quot;Ham-日程&quot;). The item&#39;s name, location, notes, time, and reminder are all synced.</p><h2 id="notification-reminders" tabindex="-1">Notification Reminders <a class="header-anchor" href="#notification-reminders" aria-label="Permalink to &quot;Notification Reminders&quot;">​</a></h2><p>If you set a reminder, Ham sends a system notification before the event starts. The notification includes the item name, location, and start time.</p><h2 id="required-permissions" tabindex="-1">Required Permissions <a class="header-anchor" href="#required-permissions" aria-label="Permalink to &quot;Required Permissions&quot;">​</a></h2><h3 id="schedule-reminders" tabindex="-1">Schedule Reminders <a class="header-anchor" href="#schedule-reminders" aria-label="Permalink to &quot;Schedule Reminders&quot;">​</a></h3><ul><li>iOS: Notifications, Calendar</li><li>Android: Notification permission</li></ul>',21)])])}const p=t(o,[["render",r]]);export{m as __pageData,p as default};
